import { Component, OnDestroy, OnInit } from '@angular/core';
import {
  combineLatest,
  debounceTime,
  filter,
  forkJoin,
  map,
  mergeMap,
  Observable,
  Subject,
  Subscription,
  switchMap,
} from 'rxjs';
import { MockDataService } from './mock-data.service';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.scss'],
})
export class AppComponent implements OnInit, OnDestroy {
  searchTermByCharacters = new Subject<string>();
  charactersResults$!: Observable<any>;
  planetAndCharactersResults$!: Observable<any>;
  isLoading: boolean = false;
  subscriptions: Subscription[] = [];

  constructor(private mockDataService: MockDataService) {}

  ngOnInit(): void {
    this.initLoadingState();
    this.initCharacterEvents();
  }

  changeCharactersInput(element: any): void {
    // 1.1. Add functionality to changeCharactersInput method. Changes searchTermByCharacters Subject value on input change.
    const inputValue: string = element.target.value;
    this.searchTermByCharacters.next(inputValue); //emit the new value to the searchTermByCharacters Subject;
  }

  initCharacterEvents(): void {
    // 1.2. Add API call on each user input. Use mockDataService.getCharacters - to make get request.

    this.charactersResults$ = this.searchTermByCharacters
      .pipe(filter(searchTerm => searchTerm.length >= 3), // 2. Since we don't want to spam our service add filter by input value and do not call API until a user enters at least 3 chars.
      debounceTime(300), // 3. Add debounce to prevent API calls until user stop typing.
      mergeMap(searchTerm => this.mockDataService.getCharacters(searchTerm))); //call the API and flatten the inner observable Osbervale<Observable<Person[]>> using mergeMap 
  }

// 4. On clicking the button 'Load Characters And Planets', it is necessary to process two requests and combine the results of both requests into one result array.
  loadCharactersAndPlanet(): void {    
    // Using forkJoin to load all characters and planets in parallel and combine results
    this.planetAndCharactersResults$ = forkJoin({
      charactersResults$: this.mockDataService.getCharacters(), // get all characters
      planetAndCharactersResults$: this.mockDataService.getPlanets() // get all planets
    }).pipe(
      map(result => [...result.charactersResults$, ...result.planetAndCharactersResults$]) // merge into one array using spread operator
    );
  }

// 5.1. Let's add loader logic to our page. For each request, we have an observable that contains the state of the request. When we send a request the value is true, when the request is completed, the value becomes false. You can get value data with mockDataService.getCharactersLoader() and mockDataService.getPlanetLoader().
  initLoadingState(): void {
    
    // Combine loader streams to manage isLoading state
    const currentSub = combineLatest([
    this.mockDataService.getCharactersLoader(),
    this.mockDataService.getPlanetLoader()
    ]).pipe(
      map(loaders => this.isAtLeastOneTrue(loaders))
    ).subscribe(val => this.isLoading = val);

  this.subscriptions.push(currentSub);
  }

  ngOnDestroy(): void {
    // 5.2 Unsubscribe from all subscriptions
    this.subscriptions.forEach(sub => sub.unsubscribe());
  }

  isAtLeastOneTrue(elements: boolean[]): boolean {
    return elements.some((el) => el);
  }
}
<loader [isLoading]="isLoading"></loader>
<div class="content">
    <div class="logo">
        <img src="https://brandpalettes.com/wp-content/uploads/2021/06/star-wars-color-codes.svg" width="100"/>
    </div>

    <input (keyup)="changeCharactersInput($event)" [placeholder]="'Search by characters'" [readonly]="isLoading"/>
    <ng-container *ngIf="charactersResults$ | async as results">
        <div *ngIf="results.length > 0; else noResults">
            <div *ngFor="let item of results">
                {{ item.name }}
            </div>
        </div>
        <ng-template #noResults> No results </ng-template>
    </ng-container>

    <button (click)="loadCharactersAndPlanet()">Load Characters And Planets</button>
    <ng-container *ngIf="planetAndCharactersResults$ | async as results">
        <div *ngIf="results.length > 0; else noResults">
            <div *ngFor="let item of results">
                {{ item.name }}
            </div>
        </div>
        <ng-template #noResults> No results </ng-template>
    </ng-container>
</div>
